class Solution {
    public int minDays(int n) {
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(n);
        int days = 0;
        Set<Integer> visited = new HashSet<>();
        while (!queue.isEmpty()) {
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                int oranges = queue.poll();
                if (oranges == 0) {
                    return days;
                }
                if (!visited.contains(oranges)) {
                    visited.add(oranges);
                    if (oranges - 1 > 0) {
                        queue.offer(oranges - 1);
                    }
                    if (oranges % 2 == 0 && oranges / 2 > 0) {
                        queue.offer(oranges / 2);
                    }
                    if (oranges % 3 == 0 && oranges / 3 > 0) {
                        queue.offer(oranges - 2 * (oranges / 3));
                    }
                }
            }
            days++;
        }
        return -1;
    }
}
